INSERT INTO `email_notifications` (`id`, `recipient`, `phone_number`, `subject`, `notification_type`, `status`, `error_message`, `created_at`, `email_body`, `sent_at`) VALUES ('296', 'mylmacamus31@gmail.com', NULL, 'Queue Ticket: #PWD-003', 'Manual Ticket Email', 'sent', 'Email sent successfully.', '2026-06-22 18:41:22', '<div style=\'font-family: sans-serif; max-width: 600px; margin: 20px auto; border: 1px solid #e2e8f0; border-radius: 12px; overflow: hidden;\'>\n        <div style=\'background-color: #4f46e5; padding: 20px; text-align: center; color: white;\'>\n            <h2 style=\'margin:0;\'>Your Queue Ticket</h2>\n        </div>\n        <div style=\'padding: 30px; line-height: 1.6; color: #334155;\'>\n            <p>Hello <strong>Mariel Macamus</strong>,</p>\n            <p>Here are the details of your queue ticket for your reference:</p>\n            <div style=\'background: #f8fafc; padding: 20px; border-radius: 8px; border-left: 4px solid #4f46e5; margin: 20px 0;\'>\n                <h1 style=\'margin: 0; color: #4f46e5; font-size: 32px;\'>#PWD-003</h1>\n                <p style=\'margin: 10px 0 0;\'><strong>Purpose:</strong> Inquiry</p>\n                <p style=\'margin: 5px 0 0;\'><strong>Status:</strong> Waiting</p>\n                <p style=\'margin: 5px 0 0;\'><strong>Generated:</strong> June 22, 2026, 6:41 PM</p>\n            </div>\n            <p>Please present this information or have your ticket ready when your number is called.</p>\n            <p style=\'font-size: 14px; color: #64748b; font-style: italic;\'>Note: Tickets are valid for 2 hours from the time of generation.</p>\n        </div>\n        <div style=\'background: #f1f5f9; padding: 15px; text-align: center; font-size: 12px; color: #64748b;\'>\n            Â© 2026 Granby College of Science and Technology\n        </div>\n    </div>', '2026-06-22 18:41:22');
