div style=\'text-align:center;margin:25px 0;padding:20px;border:2px dashed #4f46e5;border-radius:16px;background:#f8fafc;\'><div style=\'font-size:14px;font-weight:bold;color:#4f46e5;margin-bottom:15px;\'>TRANSACTION QR CODE</div><img src=\'cid:order_qr_code\' width=\'200\' height=\'200\' alt=\'QR Code\' style=\'display:block;margin:0 auto;outline:none;text-decoration:none;-ms-interpolation-mode:bicubic;\' /><p style=\'font-size:11px;color:#64748b;margin-top:10px;font-family:monospace;font-weight:bold;\'>ORDER-1783590734-d9b2427d</p></div>\n                            \n                            <div style=\'margin-top: 30px; text-align: center;\'>\n                                <p style=\'color: #64748b; font-size: 13px; font-style: italic;\'>Note: This QR code is required for the cashier to process your order.</p>\n                            </div>\n                        </div>\n                        <div style=\'background-color: #f8fafc; padding: 25px; text-align: center; border-top: 1px solid #e2e8f0;\'>\n                            <p style=\'margin: 0; color: #64748b; font-size: 12px;\'>Â© 2026 Granby Colleges of Science and Technology. All rights reserved.</p>\n                            <p style=\'margin: 8px 0 0; color: #94a3b8; font-size: 11px; line-height: 1.4;\'>This is an automated system notification. We look forward to serving you.</p>\n                        </div>\n                    </div>', '2026-07-09 17:52:20');
